func (c *current) onCall1(name, args, blockArg any) (any, error) {
	// Symbol followed by () - create FunCall
	argRecord := Record(args.([]Keyed[Node]))

	var block *BlockArg
	if blockArg != nil {
		block = blockArg.(*BlockArg)
	}

	return &FunCall{
		Fun:      name.(*Symbol),
		Args:     argRecord,
		BlockArg: block,
		Loc:      c.Loc(),
	}, nil
}

